const { mensagem, agente, ia, knowledge } = item;

function selecionarSegmentos(msg, base){
  if(!msg) return base.filter(seg => seg.id === 'resumo_readme');
  const lower = msg.toLowerCase();
  const matches = base.filter(seg => seg.palavrasChave.some(p => lower.includes(p)));
  if(matches.length){ return matches; }
  return base.filter(seg => ['resumo_readme','workflow_manual'].includes(seg.id));
}

const segmentos = selecionarSegmentos(mensagem, knowledge);
const explicacoes = segmentos.map(seg => `• ${seg.titulo}: ${seg.resumo} — ${seg.detalhes}`).join('
');

const saudacao = `Olá ${agente.nome.split(' ')[0]}, aqui é ${ia.nome}.`;
const resposta = `${saudacao}
${agente.tom ? agente.tom.replace(/^[a-z]/, c => c.toUpperCase()) : ''}
${explicacoes}

Caso precise de mais detalhes, posso citar as mensagens exibidas na interface.`.trim();

return [{
  agentId: agente.id,
  conta: agente.conta,
  agente,
  ia,
  mensagemOriginal: mensagem,
  resposta,
  segmentos
}];
